class Solution(object):
    def uniqueMorseRepresentations(self, words):
        morse = [".-","-...","-.-.","-..",".","..-.","--.","....","..",".---","-.-",".-..","--","-.","---",".--.","--.-",".-.","...","-","..-","...-",".--","-..-","-.--","--.."]
        morse_set = set()
        for word in words:
            morse_word = ''.join(morse[ord(c) - ord('a')] for c in word)
            morse_set.add(morse_word)
        return len(morse_set)
